import { portfolioData } from "../data/portfolioData";

const Skills = () => {
  const { skills } = portfolioData;

  // Combine skill groups
  const devSkills = [
    ...skills.frontend,
    ...skills.backend,
    ...skills.database,
  ];

  const otherSkills = [
    ...skills.tools,
    ...skills.concepts,
  ];

  const getSkillImage = (skill) => {
    const logos = {
      "HTML": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/html5/html5-original.svg",
      "CSS": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/css3/css3-original.svg",
      "JavaScript": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/javascript/javascript-original.svg",
      "React.js": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/react/react-original.svg",
      "Tailwind CSS": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/tailwindcss/tailwindcss-original.svg",
      "MUI": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/materialui/materialui-original.svg",
      "Node.js": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/nodejs/nodejs-original.svg",
      "Express.js": "https://cdn.simpleicons.org/express/000000",
      "REST APIs": "https://cdn.simpleicons.org/fastapi/009688",
      "MongoDB": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/mongodb/mongodb-original.svg",
      "Git": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/git/git-original.svg",
      "GitHub": "https://cdn.simpleicons.org/github/000000",
      "Postman": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/postman/postman-original.svg",
      "VS Code": "https://cdn.jsdelivr.net/gh/devicons/devicon/icons/vscode/vscode-original.svg",
      "Hostinger": "https://cdn.simpleicons.org/hostinger/673de6",
      "JWT Authentication": "https://cdn.simpleicons.org/jsonwebtokens/000000",
 "OOPS": "data:image/jpeg;base64,",
     "MVC Architecture": "data:image/png;base64,",

    };

    return logos[skill];
  };

  const SkillItem = ({ skill }) => (
    <div className="flex flex-col items-center justify-center mx-12">
      <img
        src={getSkillImage(skill)}
        alt={skill}
        className={`w-24 h-24 object-contain transition-transform duration-300 hover:scale-110 ${
          skill === "GitHub" || skill === "Express.js"
            ? "dark:invert"
            : ""
        }`}
      />
      <p className="mt-3 text-base font-medium text-gray-700 dark:text-gray-300">
        {skill}
      </p>
    </div>
  );

  return (
    <section className="py-24 overflow-hidden">
      <h2 className="text-4xl font-semibold text-center mb-16">
        Technical Skills
      </h2>

      {/* ===== Marquee 1 ===== */}
      <div className="marquee-container overflow-hidden mb-20">
        <div className="marquee-track-left whitespace-nowrap">
          {[...devSkills, ...devSkills].map((skill, index) => (
            <SkillItem key={index} skill={skill} />
          ))}
        </div>
      </div>

      {/* ===== Marquee 2 ===== */}
      <div className="marquee-container overflow-hidden">
        <div className="marquee-track-right whitespace-nowrap">
          {[...otherSkills, ...otherSkills].map((skill, index) => (
            <SkillItem key={index} skill={skill} />
          ))}
        </div>
      </div>
    </section>
  );
};

export default Skills;




